class Solution {
    public int findTheLongestBalancedSubstring(String s) {
        int maxLen = 0;
        int count = 0;
        int zeroCount = 0;
        for (char c : s.toCharArray()) {
            if (c == '0') {
                zeroCount++;
            } else {
                count++;
                maxLen = Math.max(maxLen, Math.min(zeroCount, count) * 2);
            }
        }
        return maxLen;
    }
}
```

